import React, { createContext, useContext, useState } from 'react';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [token, setToken] = useState(localStorage.getItem('jwt_token') || null);
  const [workspaceId, setWorkspaceId] = useState(localStorage.getItem('workspace_id') || null);

  const login = (jwt, workspace, email) => {
    localStorage.setItem('jwt_token', jwt);
    localStorage.setItem('workspace_id', workspace);
    if (email) localStorage.setItem('user_email', email);
    setToken(jwt);
    setWorkspaceId(workspace);
  };

  const logout = () => {
    localStorage.removeItem('jwt_token');
    localStorage.removeItem('workspace_id');
    localStorage.removeItem('user_email');
    setToken(null);
    setWorkspaceId(null);
  };

  return (
    <AuthContext.Provider value={{ token, workspaceId, login, logout, isAuthenticated: !!token }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
